# --- Sensitive Data Redaction ---

SENSITIVE_FIELDS = {
    'password', 'passwd', 'secret', 'token', 'authorization',
    'api_key', 'apikey', 'access_token', 'refresh_token',
    'credit_card', 'card_number', 'cvv', 'ssn', 'social_security',
    'private_key', 'session_id', 'cookie',
}

SENSITIVE_HEADER_KEYS = {
    'authorization', 'cookie', 'x-api-key', 'x-auth-token',
    'proxy-authorization', 'x-csrf-token',
}

REDACTED = '***REDACTED***'


def redact_value(key, value):
    """Redact sensitive values based on key name."""
    if isinstance(key, str) and key.lower() in SENSITIVE_FIELDS:
        if isinstance(value, str) and len(value) > 4:
            # Show last 4 chars for debugging token issues (e.g., wrong token ending)
            return f"{REDACTED}...{value[-4:]}"
        return REDACTED
    return value


def redact_dict(data, depth=0):
    """Recursively redact sensitive fields in a dictionary."""
    if depth > 10:
        return data
    if isinstance(data, dict):
        return {k: redact_value(k, redact_dict(v, depth + 1)) for k, v in data.items()}
    elif isinstance(data, list):
        return [redact_dict(item, depth + 1) for item in data]
    return data


def redact_headers(headers):
    """Redact sensitive headers."""
    redacted = {}
    for key, value in headers:
        if key.lower() in SENSITIVE_HEADER_KEYS:
            if len(value) > 8:
                # Show scheme and last 4 chars: "Bearer ...abcd"
                parts = value.split(' ', 1)
                if len(parts) == 2:
                    redacted[key] = f"{parts[0]} {REDACTED}...{parts[1][-4:]}"
                else:
                    redacted[key] = f"{REDACTED}...{value[-4:]}"
            else:
                redacted[key] = REDACTED
        else:
            redacted[key] = value
    return redacted


# --- Custom Log Formatter ---

class RequestContextFormatter(logging.Formatter):
    """Custom formatter that includes request context in log messages."""

    def format(self, record):
        if has_request_context():
            record.request_id = getattr(g, 'request_id', 'N/A')
            record.remote_addr = request.remote_addr
            record.method = request.method
            record.path = request.path
            record.user = getattr(g, 'current_user', 'anonymous')
        else:
            record.request_id = 'N/A'
            record.remote_addr = 'N/A'
            record.method = 'N/A'
            record.path = 'N/A'
            record.user = 'N/A'
        return super().format(record)


class JSONFormatter(logging.Formatter):
    """JSON formatter for structured logging (useful for log aggregation tools)."""

    def format(self, record):
        log_entry = {
            'timestamp': datetime.now(timezone.utc).isoformat(),
            'level': record.levelname,
            'logger': record.name,
            'message': record.getMessage(),
            'module': record.module,
            'function': record.funcName,
            'line': record.lineno,
        }

        if has_request_context():
            log_entry.update({
                'request_id': getattr(g, 'request_id', 'N/A'),
                'remote_addr': request.remote_addr,
                'method': request.method,
                'path': request.path,
                'user': getattr(g, 'current_user', 'anonymous'),
            })

        if record.exc_info and record.exc_info[0] is not None:
            log_entry['exception'] = self.formatException(record.exc_info)

        # Include any extra fields
        for key in ('request_data', 'response_data', 'duration_ms', 'status_code',
                     'auth_result', 'auth_failure_reason', 'user_agent'):
            if hasattr(record, key):
                log_entry[key] = getattr(record, key)

        return json.dumps(log_entry, default=str)


