def setup_logging(app):
    """Configure comprehensive logging for the application."""

    # Clear default handlers
    app.logger.handlers.clear()

    # Console handler with human-readable format
    console_handler = logging.StreamHandler()
    console_handler.setLevel(logging.DEBUG)
    console_formatter = RequestContextFormatter(
        fmt='%(asctime)s [%(levelname)s] [%(request_id)s] [%(user)s@%(remote_addr)s] '
            '%(method)s %(path)s - %(message)s',
        datefmt='%Y-%m-%d %H:%M:%S'
    )
    console_handler.setFormatter(console_formatter)

    # File handler with JSON format (for log aggregation: ELK, Splunk, etc.)
    json_handler = logging.handlers.RotatingFileHandler(
        'app.log',
        maxBytes=10 * 1024 * 1024,  # 10MB
        backupCount=5,
        encoding='utf-8'
    )
    json_handler.setLevel(logging.DEBUG)
    json_handler.setFormatter(JSONFormatter())

    # Error-specific file handler
    error_handler = logging.handlers.RotatingFileHandler(
        'app_errors.log',
        maxBytes=10 * 1024 * 1024,
        backupCount=10,
        encoding='utf-8'
    )
    error_handler.setLevel(logging.ERROR)
    error_handler.setFormatter(JSONFormatter())

    # Security audit log (auth events)
    security_handler = logging.handlers.RotatingFileHandler(
        'security_audit.log',
        maxBytes=10 * 1024 * 1024,
        backupCount=20,
        encoding='utf-8'
    )
    security_handler.setLevel(logging.INFO)
    security_handler.setFormatter(JSONFormatter())

    app.logger.addHandler(console_handler)
    app.logger.addHandler(json_handler)
    app.logger.addHandler(error_handler)
    app.logger.setLevel(logging.DEBUG)

    # Separate security logger
    security_logger = logging.getLogger('security')
    security_logger.addHandler(security_handler)
    security_logger.addHandler(console_handler)
    security_logger.setLevel(logging.INFO)

    return app.logger, security_logger


