VALID_TOKENS = {}


def get_request_body_safe():
    """Safely extract and redact request body data."""
    try:
        if request.is_json:
            data = request.get_json(silent=True)
            if data:
                return redact_dict(data)
        if request.form:
            return redact_dict(dict(request.form))
        raw = request.get_data(as_text=True)
        if raw and len(raw) < 10000:
            # Try to parse and redact
            try:
                parsed = json.loads(raw)
                return redact_dict(parsed)
            except (json.JSONDecodeError, TypeError):
                # Check for sensitive patterns in raw data
                redacted_raw = re.sub(
                    r'(password|token|secret|api_key)(["\s:=]+)([^\s&"\']+)',
                    rf'\1\2{REDACTED}',
                    raw,
                    flags=re.IGNORECASE
                )
                return redacted_raw
        elif raw:
            return f'<body too large: {len(raw)} bytes>'
    except Exception as e:
        return f'<error reading body: {e}>'
    return None


