# --- Authentication Decorator ---

def require_auth(f):
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            security_logger.warning(
                'Authentication failed: missing or malformed Authorization header',
                extra={
                    'auth_result': 'failure',
                    'auth_failure_reason': 'missing_token',
                }
            )
            return jsonify({'error': 'Authentication required'}), 401

        token = auth_header[7:]
        user_info = VALID_TOKENS.get(token)
        if not user_info:
            # Log failure WITHOUT the actual token
            security_logger.warning(
                'Authentication failed: invalid token',
                extra={
                    'auth_result': 'failure',
                    'auth_failure_reason': 'invalid_token',
                    # Log token fingerprint (first/last 4 chars) for debugging
                    # without exposing the full token
                    'token_fingerprint': f'{token[:4]}...{token[-4:]}' if len(token) > 8 else 'too_short',
                }
            )
            return jsonify({'error': 'Invalid token'}), 401

        g.current_user = user_info['username']
        g.current_user_role = user_info['role']
        return f(*args, **kwargs)
    return decorated


