@app.route('/api/login', methods=['POST'])
def login():
    """Login endpoint with comprehensive security logging."""
    data = request.get_json(silent=True)
    if not data:
        security_logger.warning(
            'Login attempt with missing/invalid request body',
            extra={'auth_result': 'failure', 'auth_failure_reason': 'invalid_request_body'}
        )
        return jsonify({'error': 'Invalid request body'}), 400

    username = data.get('username', '')
    # NOTE: We intentionally do NOT log the password, even for debugging
    # Instead, we log useful diagnostic info that doesn't compromise security

    if not username or 'password' not in data:
        security_logger.warning(
            f'Login attempt with missing credentials for user: {username or "empty"}',
            extra={
                'auth_result': 'failure',
                'auth_failure_reason': 'missing_credentials',
            }
        )
        return jsonify({'error': 'Username and password required'}), 400

    user = USERS_DB.get(username)
    if not user:
        security_logger.warning(
            f'Login attempt for non-existent user: {username}',
            extra={
                'auth_result': 'failure',
                'auth_failure_reason': 'user_not_found',
                # Useful for debugging without exposing password:
                'password_length': len(data.get('password', '')),
                'password_has_special_chars': bool(re.search(r'[^a-zA-Z0-9]', data.get('password', ''))),
            }
        )
        # Use same error message to prevent user enumeration
        return jsonify({'error': 'Invalid credentials'}), 401

    if not check_password_hash(user['password_hash'], data['password']):
        security_logger.warning(
            f'Login attempt with wrong password for user: {username}',
            extra={
                'auth_result': 'failure',
                'auth_failure_reason': 'wrong_password',
                # Debug hints without exposing the actual password:
                'password_length': len(data['password']),
                'password_has_uppercase': bool(re.search(r'[A-Z]', data['password'])),
                'password_has_digits': bool(re.search(r'\d', data['password'])),
            }
        )
        return jsonify({'error': 'Invalid credentials'}), 401

    # Generate token
    token = str(uuid.uuid4())
    VALID_TOKENS[token] = {
        'username': username,
        'role': user['role'],
        'created_at': datetime.now(timezone.utc).isoformat(),
    }

    security_logger.info(
        f'Successful login for user: {username}',
        extra={
            'auth_result': 'success',
            # Log token fingerprint for correlation, not the full token
            'token_fingerprint': f'{token[:4]}...{token[-4:]}',
        }
    )

    return jsonify({
        'message': 'Login successful',
        'token': token,
        'user': {
            'username': username,
            'role': user['role'],
            'email': user['email'],
        }
    })


@app.route('/api/logout', methods=['POST'])
@require_auth
def logout():
    """Logout endpoint."""
    auth_header = request.headers.get('Authorization', '')
    token = auth_header[7:] if auth_header.startswith('Bearer ') else ''

    if token in VALID_TOKENS:
        del VALID_TOKENS[token]
        security_logger.info(
            f'User logged out: {g.current_user}',
            extra={'auth_result': 'logout_success'}
        )
    return jsonify({'message': 'Logged out successfully'})


@app.route('/api/users', methods=['GET'])
@require_auth
def get_users():
    """Get all users (admin only)."""
    if g.current_user_role != 'admin':
        security_logger.warning(
            f'Unauthorized access attempt to /api/users by {g.current_user} (role: {g.current_user_role})',
            extra={'auth_result': 'authorization_failure', 'auth_failure_reason': 'insufficient_role'}
        )
        return jsonify({'error': 'Admin access required'}), 403

    users = [
        {'username': uname, 'role': udata['role'], 'email': udata['email']}
        for uname, udata in USERS_DB.items()
    ]
    logger.info(f'User list retrieved by {g.current_user}')
    return jsonify({'users': users})


